```
import dagster as dg

from datetime import datetime


class FileConfig(dg.Config):
    name: str


@dg.asset()
def example_upstream(context: dg.AssetExecutionContext, config: FileConfig):
    context.log.info(config.name)


@dg.asset(deps=[example_upstream])
def example_downstream(context: dg.AssetExecutionContext, config: FileConfig):
    context.log.info(config.name)


my_job = dg.define_asset_job("example_job", [example_upstream, example_downstream])


@dg.sensor(minimum_interval_seconds=120, job=my_job)
def my_csv_sensor() -> dg.SensorResult:
    example_detected_files = [
        {"name": "example_file_01.csv"},
        {"name": "example_file_01.csv"},
        {"name": "example_file_01.csv"},
    ]

    return dg.SensorResult(
        run_requests=[
            dg.RunRequest(
                run_config=dg.RunConfig(
                    ops={
                        "example_upstream": FileConfig(name=file.get("name")),
                        "example_downstream": FileConfig(name=file.get("name")),
                    }
                ),
            )
            for file in example_detected_files
        ],
        cursor=str(datetime.now()),  # todo - use real cursor
    )


defs = dg.Definitions(
    assets=[example_upstream, example_downstream],
    sensors=[my_csv_sensor],
)
